insert into kb_documents (category, content_he, content_ar) values
('clinic_profile', 'סוסאן Signature Smile - מרפאת שיניים יוקרתית בחיפה בניהולו של ד"ר פאדי סוסאן.', 'سوسان Signature Smile - عيادة أسنان فاخرة في حيفا بإدارة د. فادي سوسان.'),
('contact_info', 'רחוב דוגמה 1, חיפה. טלפון 04-123-4567. שעות פתיחה א-ה 09:00 עד 18:00.', 'شارع دوغما 1، حيفا. هاتف 04-123-4567. ساعات العمل من الأحد إلى الخميس 09:00 حتى 18:00.'),
('treatments', 'אנו מציעים שתלים דנטליים ביום אחד, ציפויי חרסינה פרימיום, השתלות ממוחשבות, והלבנת שיניים. המחיר לשתל נע בין 3,500 ל-6,000 ש"ח כולל כתר ותלוי במקרה הספציפי.','نقدم زراعة أسنان في يوم واحد، قشور الخزف الفاخرة، والزراعة المحوسبة. يتراوح سعر الزرعة بين 3500 و 6000 شيكل بما في ذلك التاج حسب الحالة.'),
('faq', 'האם מקבלים ילדים? אנו מרפאת פרימיום למבוגרים וטיפולים מורכבים ברובנו, אך במקרים מסוימים ניתן לתאם ייעוץ. במקרה של כאב חד או חירום, יש לפנות טלפונית למרפאה.','هل نستقبل الأطفال؟ نحن عيادة فاخرة للبالغين والعلاجات المعقدة في الغالب. في حالة الألم الشديد، يرجى الاتصال هاتفياً.');
